import React, { useContext, useEffect, useState } from 'react';
import Fade from 'react-reveal/Fade';
import Tilt from 'react-tilt';
import { Container, Row, Col } from 'react-bootstrap';
import PortfolioContext from '../../context/context';
import Title from '../Title/Title';
import { nanoid } from 'nanoid';
import ProjectImg from '../Image/ProjectImg';

const Projects = () => {
  const { projects } = useContext(PortfolioContext);

  const [isDesktop, setIsDesktop] = useState(false);
  const [isMobile, setIsMobile] = useState(false);
  const [showAll, setShowAll] = useState(false);

  useEffect(() => {
    if (window.innerWidth > 769) {
      setIsDesktop(true);
      setIsMobile(false);
    } else {
      setIsMobile(true);
      setIsDesktop(false);
    }
  }, []);

  // Show only first 4 projects by default, or all if showAll is true
  const displayedProjects = showAll ? projects : projects.slice(0, 4);

  return (
    <section id="projects">
      <Container>
        <div className="project-wrapper">
          <Title title="Some Projects" />
          {displayedProjects.map((project) => {
            const { title, info, info2, info3, involvement, url, repo, img, id } = project;

            return (
              <Row key={id} style={{ padding: `10rem 0` }}>
                <Col lg={4} sm={12}>
                  <Fade
                    left={isDesktop}
                    bottom={isMobile}
                    duration={1000}
                    delay={500}
                    distance="30px"
                  >
                    <div className="project-wrapper__text">
                      <h3 className="project-wrapper__text-title">{title || 'Project Title'}</h3>
                      <div>
                        <h4 className="project-wrapper__text-subtitle">{info || ''}</h4>
                        <div className="involvement mb-4">
                          {involvement.map((i) => {
                            return <span key={nanoid()}>{i}</span>;
                          })}
                        </div>
                        <p className="">
                          {info2 ||
                            'Lorem ipsum dolor sit, amet consectetur adipisicing elit. Excepturi neque, ipsa animi maiores repellendu distinctioaperiam earum dolor voluptatum consequatur blanditiis inventore debitis fuga numquam voluptate architecto itaque molestiae.'}
                        </p>
                        <p className="">{info3 || ''}</p>
                      </div>
                      <a
                        target="_blank"
                        rel="noopener noreferrer"
                        className="cta-btn cta-btn--hero"
                        href={url || '#!'}
                      >
                        See Live
                      </a>

                      {repo && (
                        <a
                          target="_blank"
                          rel="noopener noreferrer"
                          className="cta-btn text-color-main"
                          href={repo}
                        >
                          Source Code
                        </a>
                      )}
                    </div>
                  </Fade>
                </Col>
                <Col lg={8} sm={12}>
                  <Fade
                    right={isDesktop}
                    bottom={isMobile}
                    duration={1000}
                    delay={1000}
                    distance="30px"
                  >
                    <div className="project-wrapper__image">
                      <a
                        href={url || '#!'}
                        target="_blank"
                        aria-label="Project Link"
                        rel="noopener noreferrer"
                      >
                        <Tilt
                          options={{
                            reverse: false,
                            max: 8,
                            perspective: 1000,
                            scale: 1,
                            speed: 300,
                            transition: true,
                            axis: null,
                            reset: true,
                            easing: 'cubic-bezier(.03,.98,.52,.99)',
                          }}
                        >
                          <div data-tilt className="thumbnail rounded">
                            <ProjectImg alt={title} filename={img} />
                          </div>
                        </Tilt>
                      </a>
                    </div>
                  </Fade>
                </Col>
              </Row>
            );
          })}

          {/* See More / Show Less Button */}
          {projects.length > 4 && (
            <Row style={{ padding: `2rem 0`, justifyContent: 'center' }}>
              <Col lg={12} style={{ textAlign: 'center' }}>
                <button
                  className="cta-btn cta-btn--hero"
                  onClick={() => setShowAll(!showAll)}
                  style={{ cursor: 'pointer' }}
                >
                  {showAll ? 'Show Less' : 'See More Projects'}
                </button>
              </Col>
            </Row>
          )}
        </div>
      </Container>
    </section>
  );
};

export default Projects;
